// Change from:
import something from '{module}';

// To named import:
import {{ something }} from '{module}';

// Or enable in tsconfig.json:
// {{ "compilerOptions": {{ "esModuleInterop": true }} }}

conditions.codeBlock:
// declarations.d.ts
declare module '*.css' {
  const styles: Record<string, string>;
  export default styles;
}

// declarations.d.ts
declare module '*.svg' {
  const content: string;
  export default content;
}

// Option 1: Null check
if (value !== undefined) {
  target = value;
}

// Option 2: Default value
target = value ?? defaultValue;

// Option 3: Non-null assertion (use with caution)
target = value!;

// Null check
if (value !== null) {
  target = value;
}

// Default value
target = value ?? fallback;

// types/express.d.ts
import 'express';
declare module 'express' {
  interface Request {
    {property}?: any; // replace 'any' with proper type
  }
}

// global.d.ts
declare global {
  interface Window {
    {property}: any; // replace 'any' with proper type
  }
}

