// Double assertion (use with caution)
const result = value as unknown as TargetType;

// Better: restructure to avoid the assertion
function convert(input: SourceType): TargetType {
  return { /* map fields explicitly */ };
}

// Option 1: Null check
if (obj !== null) {
  obj.method();
}

// Option 2: Optional chaining
obj?.method();

// Option 3: Non-null assertion (if you're sure)
obj!.method();

// Option 1: Check
if (obj !== undefined) {
  obj.method();
}

// Option 2: Optional chaining
const result = obj?.method();

// Option 3: Default value
const value = obj ?? defaultValue;

// Use 'as const' to create a tuple
const args = ['hello', 42] as const;
fn(...args);

// Or explicitly type as tuple
const args: [string, number] = ['hello', 42];
fn(...args);

class MyClass {
  // Option 1: Initialize in declaration
  {property}: string = '';

  // Option 2: Definite assignment assertion
  {property}!: string;

  // Option 3: Optional property
  {property}?: string;

  // Option 4: Initialize in constructor
  constructor() {
    this.{property} = 'value';
  }
}

// In catch blocks
try {
  // ...
} catch (error) {
  if (error instanceof Error) {
    console.error(error.message);
  } else {
    console.error('Unknown error:', String(error));
  }
}

// General narrowing
function handle(value: unknown) {
  if (typeof value === 'string') {
    console.log(value.toUpperCase());
  }
}

// Add explicit type annotation to break complexity
const result: ExpectedType = complexExpression;

// Or simplify the union
type SimpleUnion = TypeA | TypeB; // instead of large computed union

// Change from:
import {{ {member} }} from '{module}';

// To:
import {suggestion} from '{module}';

// Wrong: using interface as value
interface MyType { x: number }
if (value instanceof MyType) {} // Error!

// Correct: use type guard
function isMyType(value: unknown): value is MyType {
  return typeof value === 'object' && value !== null && 'x' in value;
}

// If you want the type of a variable:
const config = { port: 3000 };
type Config = typeof config; // { port: number }

// If you want the return type of a function:
type Result = ReturnType<typeof myFunction>;

