// Null check
if ({name} !== null) {
  {name}.doSomething();
}

// Optional chaining
{name}?.doSomething();

// Non-null assertion (use with caution)
{name}!.doSomething();

// Undefined check
if ({name} !== undefined) {
  {name}.doSomething();
}

// Optional chaining
{name}?.doSomething();

// Default value
const value = {name} ?? defaultValue;

// Narrow the type
if (typeof key === 'string') {
  const value = obj[key];
}

// Or convert
const value = obj[String(key)];

// Example: constraint requires specific shape
interface HasId {
  id: string;
}

function getById<T extends HasId>(items: T[], id: string): T | undefined {
  return items.find(item => item.id === id);
}

// Type passed must have 'id: string'
getById([{ id: '1', name: 'test' }], '1'); // OK
